import { useEffect, useRef, useState } from "react";

const WIDTH = 400;
const HEIGHT = 300;

export default function DuckHunt() {
  const [score, setScore] = useState(0);
  const [duck, setDuck] = useState({
    x: 0,
    y: 0,
    alive: true,
  });

  const timer = useRef();

  function spawnDuck() {
    setDuck({
      x: Math.random() * (WIDTH - 50),
      y: Math.random() * (HEIGHT - 50),
      alive: true,
    });

    timer.current = setTimeout(spawnDuck, 1500);
  }

  function shootDuck() {
    if (!duck.alive) return;

    clearTimeout(timer.current);

    setScore((score) => score + 1);

    setDuck((duck) => ({
      ...duck,
      alive: false,
    }));

    timer.current = setTimeout(spawnDuck, 200);
  }

  useEffect(() => {
    spawnDuck();

    return () => clearTimeout(timer.current);
  }, []);

  return (
    <main>
      <h1>🔫 Duck Hunt</h1>

      <p>Score: {score}</p>

      <article
        style={{
          position: "relative",
          width: WIDTH,
          height: HEIGHT,
          border: "2px solid currentColor",
          cursor: "crosshair",
          overflow: "hidden",
        }}
      >
        <button
          onClick={shootDuck}
          style={{
            position: "absolute",
            left: duck.x,
            top: duck.y,
            border: "none",
            background: "none",
            padding: 0,
            fontSize: "2.5rem",
            cursor: "crosshair",
          }}
        >
          {duck.alive ? "🦆" : "💥"}
        </button>
      </article>
    </main>
  );
}
